func findTheDifference(s string, t string) byte {
	letters := make([]int, 26)
	for _, c := range s {
		letters[c-'a']++
	}
	for _, c := range t {
		letters[c-'a']--
	}
	for i, count := range letters {
		if count == -1 {
			return byte('a' + i)
		}
	}

	return 'a'
}

